const wordCount = (text) => text.trim().split(/\s+/).filter(Boolean).length;

let payload = {
  bookId: $('When Executed by Another Workflow').first().json.bookId,
  chapterSequence: $('When Executed by Another Workflow').first().json.sequence,
  status: "success",
  title: $('When Executed by Another Workflow').first().json.title,
  content: "",
  topics: [
    { title: $('When Executed by Another Workflow').first().json.topics[0].title, content: $('Set topic_content capX topic 01').first().json.topic_content },
    { title: $('When Executed by Another Workflow').first().json.topics[1].title, content: $('Set topic_content capX topic 02').first().json.topic_content }
  ],
  contextSummary: $('Set context capX topic 01').first().json.context+$input.first().json.context,
  wordCount: 0
};

const totalWords = wordCount(JSON.stringify(payload.topics));

payload.wordCount = totalWords;

return payload;

return {
  bookId: $('When Executed by Another Workflow').first().json.bookId,
  context: String($('TUNNEL').first().json.context || "") + $('Set context capX topic 01').first().json.context + " " + $('Set context capX topic 02').first().json.context
}
